 180→/**
 181→ * Create a workspace record in SurrealDB for proxy testing.
 182→ */
 183→export async function createProxyTestWorkspace(
 184→  surreal: Surreal,
 185→  workspaceId: string,
 186→  options?: { dailyBudget?: number; alertThreshold?: number },
 187→): Promise<string> {
 188→  const workspaceRecord = new RecordId("workspace", workspaceId);
 189→
 190→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
 191→    workspace: workspaceRecord,
 192→    content: {
 193→      name: `Proxy Test Workspace ${workspaceId}`,
 194→      status: "active",
 195→      onboarding_complete: true,
 196→      onboarding_turn_count: 0,
 197→      onboarding_summary_pending: false,
 198→      onboarding_started_at: new Date(),
 199→      created_at: new Date(),
 200→      proxy_settings: {
 201→        daily_budget: options?.dailyBudget ?? 50.0,
 202→        alert_threshold: options?.alertThreshold ?? 0.8,
 203→        rate_limit_per_minute: 60,
 204→      },
 205→    },
 206→  });
 207→
 208→  return workspaceId;
 209→}
