 235→/**
 236→ * Create a task record linked to a project and workspace.
 237→ */
 238→export async function createProxyTestTask(
 239→  surreal: Surreal,
 240→  taskId: string,
 241→  projectId: string,
 242→  workspaceId: string,
 243→): Promise<string> {
 244→  const taskRecord = new RecordId("task", taskId);
 245→  const projectRecord = new RecordId("project", projectId);
 246→  const workspaceRecord = new RecordId("workspace", workspaceId);
 247→
 248→  await surreal.query(`CREATE $task CONTENT $content;`, {
 249→    task: taskRecord,
 250→    content: {
 251→      title: `Test Task ${taskId}`,
 252→      status: "open",
 253→      workspace: workspaceRecord,
 254→      created_at: new Date(),
 255→    },
 256→  });
 257→
 258→  // Link task to project
 259→  await surreal.query(`RELATE $task->belongs_to->$project SET created_at = time::now();`, {
 260→    task: taskRecord,
 261→    project: projectRecord,
 262→  });
 263→
 264→  return taskId;
 265→}
