 270→
 271→export type LlmTraceRecord = {
 272→  id: RecordId;
 273→  model: string;
 274→  input_tokens: number;
 275→  output_tokens: number;
 276→  cache_creation_tokens?: number;
 277→  cache_read_tokens?: number;
 278→  cost_usd: number;
 279→  latency_ms: number;
 280→  stop_reason?: string;
 281→  request_id?: string;
 282→  created_at: Date;
 283→};
 284→
 285→/**
 286→ * Query all LLM traces in a workspace.
 287→ */
 288→export async function getTracesForWorkspace(
 289→  surreal: Surreal,
 290→  workspaceId: string,
 291→): Promise<LlmTraceRecord[]> {
 292→  const workspaceRecord = new RecordId("workspace", workspaceId);
 293→
 294→  const results = await surreal.query(
 295→    `SELECT * FROM trace WHERE ->scoped_to->workspace CONTAINS $ws ORDER BY created_at DESC;`,
 296→    { ws: workspaceRecord },
 297→  );
 298→
 299→  return (results[0] ?? []) as LlmTraceRecord[];
 300→}
