 319→/**
 320→ * Check whether a trace has the expected graph edges.
 321→ */
 322→export async function getTraceEdges(
 323→  surreal: Surreal,
 324→  traceId: string,
 325→): Promise<{
 326→  workspaces: RecordId[];
 327→  tasks: RecordId[];
 328→  sessions: RecordId[];
 329→}> {
 330→  const traceRecord = new RecordId("trace", traceId);
 331→
 332→  const results = await surreal.query(
 333→    `SELECT
 334→       ->scoped_to->workspace AS workspaces,
 335→       ->attributed_to->task AS tasks,
 336→       <-invoked<-agent_session AS sessions
 337→     FROM $trace;`,
 338→    { trace: traceRecord },
 339→  );
 340→
 341→  const row = (results[0] as Array<{
 342→    workspaces: RecordId[];
 343→    tasks: RecordId[];
 344→    sessions: RecordId[];
 345→  }>)?.[0];
 346→
 347→  return {
 348→    workspaces: row?.workspaces ?? [],
 349→    tasks: row?.tasks ?? [],
 350→    sessions: row?.sessions ?? [],
 351→  };
 352→}
