 354→/**
 355→ * Query the total spend for a workspace (sum of trace costs).
 356→ */
 357→export async function getWorkspaceSpend(
 358→  surreal: Surreal,
 359→  workspaceId: string,
 360→): Promise<number> {
 361→  const workspaceRecord = new RecordId("workspace", workspaceId);
 362→
 363→  const results = await surreal.query(
 364→    `SELECT math::sum(cost_usd) AS total FROM trace WHERE ->scoped_to->workspace CONTAINS $ws;`,
 365→    { ws: workspaceRecord },
 366→  );
 367→
 368→  const row = (results[0] as Array<{ total: number }>)?.[0];
 369→  return row?.total ?? 0;
 370→}
