 372→/**
 373→ * Seed an LLM trace directly for testing dashboard/audit scenarios
 374→ * that need pre-existing trace data.
 375→ */
 376→export async function seedLlmTrace(
 377→  surreal: Surreal,
 378→  traceId: string,
 379→  options: {
 380→    model: string;
 381→    input_tokens: number;
 382→    output_tokens: number;
 383→    cost_usd: number;
 384→    latency_ms: number;
 385→    workspaceId: string;
 386→    taskId?: string;
 387→    sessionId?: string;
 388→    stop_reason?: string;
 389→    cache_read_tokens?: number;
 390→    cache_creation_tokens?: number;
 391→    created_at?: Date;
 392→  },
 393→): Promise<string> {
 394→  const traceRecord = new RecordId("trace", traceId);
 395→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
 396→
 397→  await surreal.query(`CREATE $trace CONTENT $content;`, {
 398→    trace: traceRecord,
 399→    content: {
 400→      model: options.model,
 401→      input_tokens: options.input_tokens,
 402→      output_tokens: options.output_tokens,
 403→      cache_read_tokens: options.cache_read_tokens ?? 0,
 404→      cache_creation_tokens: options.cache_creation_tokens ?? 0,
 405→      cost_usd: options.cost_usd,
 406→      latency_ms: options.latency_ms,
 407→      stop_reason: options.stop_reason ?? "end_turn",
 408→      created_at: options.created_at ?? new Date(),
 409→    },
 410→  });
 411→
 412→  // Create workspace edge
 413→  await surreal.query(
 414→    `RELATE $trace->scoped_to->$workspace SET created_at = time::now();`,
 415→    { trace: traceRecord, workspace: workspaceRecord },
 416→  );
 417→
 418→  // Create task edge if provided
 419→  if (options.taskId) {
 420→    const taskRecord = new RecordId("task", options.taskId);
 421→    await surreal.query(
 422→      `RELATE $trace->attributed_to->$task SET created_at = time::now();`,
 423→      { trace: traceRecord, task: taskRecord },
 424→    );
 425→  }
 426→
 427→  // Create session edge if provided
 428→  if (options.sessionId) {
 429→    const sessionRecord = new RecordId("agent_session", options.sessionId);
 430→    await surreal.query(
 431→      `RELATE $session->invoked->$trace SET created_at = time::now();`,
 432→      { trace: traceRecord, session: sessionRecord },
 433→    );
 434→  }
 435→
 436→  return traceId;
 437→}
