 443→/**
 444→ * Create a model access policy for the proxy.
 445→ */
 446→export async function createModelAccessPolicy(
 447→  surreal: Surreal,
 448→  workspaceId: string,
 449→  options: {
 450→    policyId: string;
 451→    agentType: string;
 452→    allowedModels: string[];
 453→    status?: string;
 454→  },
 455→): Promise<string> {
 456→  const policyRecord = new RecordId("policy", options.policyId);
 457→  const workspaceRecord = new RecordId("workspace", workspaceId);
 458→
 459→  await surreal.query(`CREATE $policy CONTENT $content;`, {
 460→    policy: policyRecord,
 461→    content: {
 462→      title: `Model Access: ${options.agentType}`,
 463→      description: `Controls which models ${options.agentType} can use`,
 464→      status: options.status ?? "active",
 465→      version: 1,
 466→      workspace: workspaceRecord,
 467→      rules: [{
 468→        id: "model_access",
 469→        condition: { field: "agent_type", operator: "eq", value: options.agentType },
 470→        effect: "allow",
 471→        priority: 50,
 472→        params: { allowed_models: options.allowedModels },
 473→      }],
 474→      created_at: new Date(),
 475→    },
 476→  });
 477→
 478→  return options.policyId;
