 583→/**
 584→ * Create a proxy_intelligence_config record for a workspace.
 585→ * Controls context injection, contradiction detection, and session timeout.
 586→ */
 587→export async function createProxyIntelligenceConfig(
 588→  surreal: Surreal,
 589→  workspaceId: string,
 590→  options?: {
 591→    contextInjectionEnabled?: boolean;
 592→    contextInjectionTokenBudget?: number;
 593→    contextInjectionCacheTtlSeconds?: number;
 594→    contextInjectionTier?: "fast" | "secure";
 595→    contradictionDetectionEnabled?: boolean;
 596→    contradictionTier1Threshold?: number;
 597→    contradictionTier2ConfidenceMin?: number;
 598→    sessionTimeoutMinutes?: number;
 599→  },
 600→): Promise<string> {
 601→  const configId = `cfg-${workspaceId}`;
 602→  const configRecord = new RecordId("proxy_intelligence_config", configId);
 603→  const workspaceRecord = new RecordId("workspace", workspaceId);
 604→
 605→  await surreal.query(`CREATE $config CONTENT $content;`, {
 606→    config: configRecord,
 607→    content: {
 608→      workspace: workspaceRecord,
 609→      context_injection_enabled: options?.contextInjectionEnabled ?? true,
 610→      context_injection_token_budget: options?.contextInjectionTokenBudget ?? 1000,
 611→      context_injection_cache_ttl_seconds: options?.contextInjectionCacheTtlSeconds ?? 300,
 612→      context_injection_tier: options?.contextInjectionTier ?? "secure",
 613→      contradiction_detection_enabled: options?.contradictionDetectionEnabled ?? true,
 614→      contradiction_tier1_threshold: options?.contradictionTier1Threshold ?? 0.75,
 615→      contradiction_tier2_confidence_min: options?.contradictionTier2ConfidenceMin ?? 0.6,
 616→      session_timeout_minutes: options?.sessionTimeoutMinutes ?? 10,
 617→      created_at: new Date(),
 618→      updated_at: new Date(),
 619→    },
 620→  });
 621→
 622→  return configId;
 623→}
