 637→  external_session_id?: string;
 638→};
 639→
 640→/**
 641→ * Query agent sessions for a workspace, optionally filtered by source.
 642→ */
 643→export async function getSessionsForWorkspace(
 644→  surreal: Surreal,
 645→  workspaceId: string,
 646→  options?: { source?: string },
 647→): Promise<AgentSessionRecord[]> {
 648→  const workspaceRecord = new RecordId("workspace", workspaceId);
 649→
 650→  const sourceFilter = options?.source
 651→    ? `AND source = $source`
 652→    : "";
 653→
 654→  const results = await surreal.query(
 655→    `SELECT * FROM agent_session WHERE workspace = $ws ${sourceFilter} ORDER BY started_at DESC;`,
 656→    { ws: workspaceRecord, source: options?.source },
 657→  );
 658→
 659→  return (results[0] ?? []) as AgentSessionRecord[];
 660→}
