 679→/**
 680→ * Seed an agent session directly for testing scenarios
 681→ * that need pre-existing session data.
 682→ */
 683→export async function seedAgentSession(
 684→  surreal: Surreal,
 685→  sessionId: string,
 686→  options: {
 687→    workspaceId: string;
 688→    agent?: string;
 689→    source?: string;
 690→    externalSessionId?: string;
 691→    startedAt?: Date;
 692→    lastActivityAt?: Date;
 693→    endedAt?: Date;
 694→  },
 695→): Promise<string> {
 696→  const sessionRecord = new RecordId("agent_session", sessionId);
 697→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
 698→
 699→  const content: Record<string, unknown> = {
 700→    agent: options.agent ?? "coding-agent",
 701→    workspace: workspaceRecord,
 702→    started_at: options.startedAt ?? new Date(),
 703→    last_activity_at: options.lastActivityAt ?? new Date(),
 704→    source: options.source ?? "proxy",
 705→    created_at: new Date(),
 706→  };
 707→
 708→  if (options.externalSessionId) {
 709→    content.external_session_id = options.externalSessionId;
 710→  }
 711→  if (options.endedAt) {
 712→    content.ended_at = options.endedAt;
 713→  }
 714→
 715→  await surreal.query(`CREATE $session CONTENT $content;`, {
 716→    session: sessionRecord,
 717→    content,
 718→  });
 719→
 720→  return sessionId;
 721→}
