 723→/**
 724→ * Simulate a session becoming stale by backdating last_activity_at.
 725→ * This allows testing the background sweep timeout behavior.
 726→ */
 727→export async function simulateSessionTimeout(
 728→  surreal: Surreal,
 729→  sessionId: string,
 730→  minutesAgo: number,
 731→): Promise<void> {
 732→  const sessionRecord = new RecordId("agent_session", sessionId);
 733→  const staleTime = new Date(Date.now() - minutesAgo * 60 * 1000);
 734→
 735→  await surreal.query(
 736→    `UPDATE $session SET last_activity_at = $staleTime;`,
